36:0dc|impl Echo {
37:562|    async fn handle_connection(self, connection: Connection) -> Result<()> {
38:26d|        // We can get the remote's node id from the connection.
39:145|        self.sleep_manager.wake_up();
40:f92|        let res = self.handle_connection2(&connection).await;
41:3fe|        if let Err(e) = res.as_ref() {
42:ff1|            warn!("Failed to handle connection: {e}");
43:b18|        }
44:d05|
45:98f|        res
46:b18|    }
47:6c0|    async fn handle_connection2(&self, connection: &Connection) -> Result<()> {
48:26d|        // We can get the remote's node id from the connection.
49:61c|        let response_own_node_id = *self.own_endpoint_node_id.as_bytes();
50:d05|
51:136|        // Our protocol is a simple request-response protocol, so we expect the
52:0f3|        // connecting peer to open a single bi-directional stream.
53:aae|        let (mut send, mut recv) = connection.accept_bi().await?;
54:d05|
55:ee6|        let mut recv_buf = vec![0; 32];
56:14b|        n0_future::time::timeout(CONNECT_TIMEOUT, recv.read_exact(&mut recv_buf))
57:dcc|            .await
58:ed9|            .context("echo")?
59:80e|            .context("echo")?;
60:0c0|        if recv_buf != connection.remote_node_id()?.as_bytes().to_vec() {
61:7bc|            return Err(anyhow::anyhow!("Invalid node id"));
62:b18|        }
63:d05|
64:bb9|        n0_future::time::timeout(CONNECT_TIMEOUT, send.write_all(&response_own_node_id))
65:dcc|            .await
66:ed9|            .context("echo")?
67:80e|            .context("echo")?;
68:d05|
69:339|        // By calling `finish` on the send stream we signal that we will not send anything
70:f8d|        // further, which makes the receive stream on the other end terminate.
71:69c|        send.finish()?;
72:d05|
73:3e7|        // Wait until the remote closes the connection, which it does once it
74:293|        // received the response.
75:f31|        connection.closed().await;
76:8d4|        Ok(())
77:b18|    }
